function Rv({ children, delay = 0 }) {
  const ref = useRef();
  const [vis, setVis] = useState(false);
  useEffect(() => {
    if (!ref.current) return;
    const obs = new IntersectionObserver(
      ([e]) => { if (e.isIntersecting) { setVis(true); obs.unobserve(e.target); } },
      { threshold: 0.06 }
    );
    obs.observe(ref.current);
    return () => obs.disconnect();
  }, []);
  return (
    <div ref={ref} style={{
      opacity: vis ? 1 : 0,
      transform: vis ? "translateY(0)" : "translateY(22px)",
      transition: `opacity 0.65s ease ${delay}ms, transform 0.65s cubic-bezier(.16,1,.3,1) ${delay}ms`
    }}>
      {children}
    </div>
  );
}

function Break() {
  return (
    <div style={{ display:"flex", alignItems:"center", gap:16, padding:"0 48px", margin:"56px 0" }}>
      <div style={{ flex:1, height:1, background:"#2a2725" }} />
      <div style={{ width:6, height:6, background:"#a82020" }} />
      <div style={{ flex:1, height:1, background:"#2a2725" }} />
    </div>
  );
}

function WallCard({ item, onClick }) {
  const [hov, setHov] = useState(false);
  return (
    <div
      onClick={onClick}
      onMouseEnter={() => setHov(true)}
      onMouseLeave={() => setHov(false)}
      style={{
        position:"relative", overflow:"hidden", cursor:"pointer",
        height: item.h, marginBottom:12,
        background: item.bg || "#141110",
        transform: hov ? "scale(1.012)" : "scale(1)",
        transition: "transform 0.35s cubic-bezier(.16,1,.3,1)",
      }}
    >
      {item.image_url && (
        <img src={item.image_url} alt={item.artist}
          style={{ width:"100%", height:"100%", objectFit:"cover", display:"block",
            transform: hov ? "scale(1.05)" : "scale(1)",
            transition: "transform 0.55s cubic-bezier(.16,1,.3,1)" }}
        />
      )}
      {/* Credit overlay - artist name LEFT, source RIGHT */}
      <div style={{
        position:"absolute", bottom:0, left:0, right:0,
        padding:"16px 20px",
        background:"linear-gradient(to top, rgba(10,8,8,0.92) 0%, transparent 100%)",
        display:"flex", justifyContent:"space-between", alignItems:"flex-end",
        opacity: hov ? 1 : 0, transition:"opacity 0.28s ease",
      }}>
        <span style={{
          fontFamily:"'Anton',sans-serif", fontSize:13,
          textTransform:"uppercase", letterSpacing:2, color:"#e0dcd6",
          lineHeight:1.2,
        }}>
          {item.artist || item.artist_name || "Unknown"}
          {item.year && (
            <span style={{ display:"block", fontFamily:"'Courier Prime',monospace",
              fontSize:10, color:"#8a6830", letterSpacing:2, marginTop:3 }}>
              {item.year}
            </span>
          )}
        </span>
        {item.source && item.source !== "#" ? (
          <a href={item.source} target="_blank" rel="noreferrer"
            onClick={e => e.stopPropagation()}
            style={{ fontFamily:"'Courier Prime',monospace", fontSize:10,
              color:"#a82020", letterSpacing:1, textTransform:"uppercase",
              textDecoration:"none", transition:"color 0.2s", flexShrink:0 }}
            onMouseEnter={e => e.target.style.color="#4888ff"}
            onMouseLeave={e => e.target.style.color="#a82020"}>
            Source
          </a>
        ) : (
          <span style={{ fontFamily:"'Courier Prime',monospace", fontSize:10,
            color:"#4888ff", letterSpacing:1, textTransform:"uppercase", flexShrink:0 }}>
            View
          </span>
        )}
      </div>
    </div>
  );
}

function MasonryWall({ items, onCardClick }) {
  const cols = [[], []];
items.forEach((item, i) => cols[i % 2].push({ ...item, _idx: i }));
  return (
    <div style={{ display:"grid", gridTemplateColumns:"repeat(2,1fr)", gap:12, padding:"0 48px" }}>
      {cols.map((col, ci) => (
        <div key={ci}>
          {col.map((item, ii) => (
            <Rv key={ii} delay={ci * 50 + ii * 70}>
              <WallCard item={item} onClick={() => onCardClick && onCardClick(item)} />
            </Rv>
          ))}
        </div>
      ))}
    </div>
  );
}

